            cudaMemcpyAsync(
                vec->gpu_action_mask + agent_start * MY_ACTION_MASK,
                vec->action_mask     + agent_start * MY_ACTION_MASK,
                agents_per_buffer * MY_ACTION_MASK * sizeof(unsigned char),
                cudaMemcpyHostToDevice, stream);
